local StructDreamTripFriendInfo = LxClass("StructDreamTripFriendInfo", nil)
function StructDreamTripFriendInfo:StructDreamTripFriendInfo()
	---@type number 平台索引
	self.index = 0
	---@type table<StructPlayerInfo> 玩家信息
	self.info = {}
end

function StructDreamTripFriendInfo:CreateByPb(pb)
	self.index = pb.index

	self.info = {}
	local info = pb.info
	local rankItem = pb.rankItem
	for i,v in ipairs(info) do
		local playerInfo = StructPlayerInfo:New()
		playerInfo:CreateByPb(v)
		local playerServerData = playerInfo:GetServerData()
		local itemNum = rankItem[i] or 0
		table.insert(self.info,{
			playerInfo = playerServerData,
			rankItem = itemNum,
		})
	end
end

function StructDreamTripFriendInfo:GetServerData()
	return {
		index = self.index,
		info = self.info,
	}
end

return StructDreamTripFriendInfo